def validate(args, output):
    mat = args[0]
    m = len(mat)
    n = len(mat[0])
    if not isinstance(output, (list, tuple)) or len(output) != 2:
        return False
    i, j = output
    if not (isinstance(i, int) and isinstance(j, int)):
        return False
    if i < 0 or i >= m or j < 0 or j >= n:
        return False
    def g(a, b):
        if 0 <= a < m and 0 <= b < n:
            return mat[a][b]
        return -1
    c = mat[i][j]
    return all(g(i + di, j + dj) < c for di, dj in ((1, 0), (-1, 0), (0, 1), (0, -1)))

