function validate(args, output) {
    const mat = args[0];
    const m = mat.length, n = mat[0].length;
    if (!Array.isArray(output) || output.length !== 2) return false;
    const i = output[0], j = output[1];
    if (!Number.isInteger(i) || !Number.isInteger(j)) return false;
    if (i < 0 || i >= m || j < 0 || j >= n) return false;
    const g = (a, b) => (a >= 0 && a < m && b >= 0 && b < n) ? mat[a][b] : -1;
    const c = mat[i][j];
    const dirs = [[1, 0], [-1, 0], [0, 1], [0, -1]];
    return dirs.every(([di, dj]) => g(i + di, j + dj) < c);
}

