def gen(rng, size):
    side = max(1, min(40, int(size ** 0.5) + 1))
    m = rng.randint(1, side)
    n = rng.randint(1, side)
    while True:
        mat = [[rng.randint(1, 100000) for _ in range(n)] for _ in range(m)]
        ok = True
        for i in range(m):
            for j in range(n):
                if i + 1 < m and mat[i][j] == mat[i + 1][j]:
                    ok = False
                if j + 1 < n and mat[i][j] == mat[i][j + 1]:
                    ok = False
            if not ok:
                break
        if ok:
            return [mat]

