class Solution:
    def findPeakGrid(self, mat):
        m = len(mat)
        n = len(mat[0])
        def g(i, j):
            if 0 <= i < m and 0 <= j < n:
                return mat[i][j]
            return -1
        for i in range(m):
            for j in range(n):
                c = mat[i][j]
                if g(i - 1, j) < c and g(i + 1, j) < c and g(i, j - 1) < c and g(i, j + 1) < c:
                    return [i, j]
        return [-1, -1]

