var findPeakGrid = function(mat) {
    const m = mat.length, n = mat[0].length;
    const g = (i, j) => (i >= 0 && i < m && j >= 0 && j < n) ? mat[i][j] : -1;
    for (let i = 0; i < m; i++) {
        for (let j = 0; j < n; j++) {
            const c = mat[i][j];
            if (g(i - 1, j) < c && g(i + 1, j) < c && g(i, j - 1) < c && g(i, j + 1) < c) {
                return [i, j];
            }
        }
    }
    return [-1, -1];
};
